<script setup lang="ts">import { computed } from 'vue'; const props=defineProps<{ value: string | boolean }>(); const map:Record<string,{text:string;type:''|'success'|'warning'|'danger'|'info'}>={consume:{text:'成功',type:'success'},error:{text:'错误',type:'danger'},up:{text:'正常',type:'success'},down:{text:'异常',type:'danger'},running:{text:'运行中',type:'success'},stopped:{text:'已停止',type:'danger'},enabled:{text:'启用',type:'success'},disabled:{text:'停用',type:'info'},auto_disabled:{text:'自动停用',type:'warning'},critical:{text:'严重',type:'danger'},warning:{text:'警告',type:'warning'},info:{text:'提示',type:'info'},online:{text:'在线',type:'success'},offline:{text:'离线',type:'danger'},pending:{text:'待处理',type:'warning'},delivered:{text:'已投递',type:'info'},succeeded:{text:'成功',type:'success'},failed:{text:'失败',type:'danger'},expired:{text:'已过期',type:'danger'},exhausted:{text:'死信',type:'danger'},firing:{text:'告警中',type:'danger'},silenced:{text:'已静默',type:'warning'},resolved:{text:'已恢复',type:'success'},acknowledged:{text:'已确认',type:'info'}}; const item=computed(()=>map[String(props.value)]||{text:String(props.value),type:'info' as const});</script>
<template><el-tag :type="item.type" size="small">{{ item.text }}</el-tag></template>
